import type { OpenAPIV2, OpenAPIV3, OpenAPIV3_1 } from 'openapi-types'

type SwaggerObject = {
  swaggerObject: Partial<OpenAPIV2.Document>
}

type OpenAPIObject = {
  openapiObject: Partial<OpenAPIV3.Document | OpenAPIV3_1.Document>
}

export const assertIsOpenAPIObject: (
  obj: SwaggerObject | OpenAPIObject,
) => asserts obj is OpenAPIObject = (obj) => {
  if ('swaggerObject' in obj) {
    throw new Error('This package currently does not support component references for Swagger 2.0')
  }
}

export type JSONSchemaTarget = 'draft-2020-12' | 'openapi-3.0'

export const getReferenceUri = (input: string): string => {
  const id = input.replace(/^#\/(?:\$defs|definitions|components\/schemas)\//, '')

  return `#/components/schemas/${id}`
}

export const getJSONSchemaTarget = (version = '3.0.0'): JSONSchemaTarget => {
  if (version.startsWith('3.0')) {
    return 'openapi-3.0'
  }

  return 'draft-2020-12'
}

'use strict'

const { Bench } = require('tinybench')
const sjson = require('..')

const internals = {
  text: '{ "a": 5, "b": 6, "proto": { "x": 7 }, "c": { "d": 0, "e": "text", "\\u005f\\u005fproto": { "y": 8 }, "f": { "g": 2 } } }',
  suspectRx: /"(?:_|\\u005f)(?:_|\\u005f)(?:p|\\u0070)(?:r|\\u0072)(?:o|\\u006f)(?:t|\\u0074)(?:o|\\u006f)(?:_|\\u005f)(?:_|\\u005f)"/
}

internals.reviver = function (key, value) {
  if (key.match(internals.suspectRx)) {
    return undefined
  }

  return value
}

const benchmark = new Bench({
  name: 'no __proto__ benchmark',
  iterations: 10000,
  warmupIterations: 100
})

benchmark
  .add('JSON.parse', () => {
    JSON.parse(internals.text)
  })
  .add('secure-json-parse parse', () => {
    sjson.parse(internals.text)
  })
  .add('secure-json-parse safeParse', () => {
    sjson.safeParse(internals.text)
  })
  .add('reviver', () => {
    JSON.parse(internals.text, internals.reviver)
  })
  .run()
  .then(() => {
    console.log(benchmark.name)
    console.table(benchmark.table())
  })

'use strict'

const randomBytes = require('node:crypto').randomBytes

const cacheSize = 24 << 7
let pos = 0
let cache = randomBytes(cacheSize)

const EQUAL_END_REGEXP = /=/g
const PLUS_GLOBAL_REGEXP = /\+/g
const SLASH_GLOBAL_REGEXP = /\//g

module.exports = function (useBase64Url = Buffer.isEncoding('base64url')) {
  return useBase64Url
    ? function idGenerator () {
      if ((pos + 24) > cacheSize) {
        cache = randomBytes(cacheSize)
        pos = 0
      }
      const buf = Buffer.allocUnsafe(24)
      cache.copy(buf, 0, pos, (pos += 24))
      return buf.toString('base64url')
    }
    : function idGenerator () {
      if ((pos + 24) > cacheSize) {
        cache = randomBytes(cacheSize)
        pos = 0
      }
      const buf = Buffer.allocUnsafe(24)
      cache.copy(buf, 0, pos, (pos += 24))
      return buf.toString('base64')
        .replace(EQUAL_END_REGEXP, '')
        .replace(PLUS_GLOBAL_REGEXP, '-')
        .replace(SLASH_GLOBAL_REGEXP, '_')
    }
}

import { Links, Meta, Outlet, Scripts, ScrollRestoration } from "react-router";
import type { LinksFunction } from "react-router";

import "./app.css";

export const links: LinksFunction = () => [
  { rel: "preconnect", href: "https://fonts.googleapis.com" },
  {
    rel: "preconnect",
    href: "https://fonts.gstatic.com",
    crossOrigin: "anonymous",
  },
  {
    rel: "stylesheet",
    href: "https://fonts.googleapis.com/css2?family=Inter:ital,opsz,wght@0,14..32,100..900;1,14..32,100..900&display=swap",
  },
];

export function Layout({ children }: { children: React.ReactNode }) {
  return (
    <html lang="en">
      <head>
        <meta charSet="utf-8" />
        <meta name="viewport" content="width=device-width, initial-scale=1" />
        <Meta />
        <Links />
      </head>
      <body>
        {children}
        <ScrollRestoration />
        <Scripts />
      </body>
    </html>
  );
}

export default function App() {
  return <Outlet />;
}

'use strict'
const fastify = require('fastify')
const app = fastify({
  logger: true
})

app.addHook('onRequest', function hook (request, reply, done) {
  request.log.info('Is a 404 HTTP request? %s', request.is404)
  done()
})

const niceHtmlPage = `<html>
<head>
  <title>Page not found</title>
  <style type=text/css>
    body{
      display: flex;
      justify-content: center;
      align-items: center;
    }

    h1 {
      font-family: sans-serif;
    }
  </style>
</head>
<body>
  <h1>Error 404</h1>
</body>
</html>`

app.register(async function plugin (instance, opts) {
  instance.setNotFoundHandler(function html404 (request, reply) {
    reply.type('text/html').send(niceHtmlPage)
  })
}, { prefix: '/site' }) // [1]

app.setNotFoundHandler(function custom404 (request, reply) {
  reply.send({ not: 'found' })
})

app.listen({
  port: 8080,
  host: '0.0.0.0'
})
  .then((address) => {
    // Started
  })
